        const nc = c + dc;                   // assignment + binding(nc) + binding(c) + binding(dc)
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) count++; // conditional + 4 bindings + 2 constants + assignment(count++)
