    }
    return count;                            // binding(count)
  };
  const result: boolean[][] = [];            // assignment + binding(result) + constant([])
  for (let r = 0; r < rows; r++) {          // loop + assignment(r) + constant(0) + binding(rows) + assignment(r++)
    const row: boolean[] = [];              // assignment + binding(row) + constant([])
